        ///<summary>
        ///Get committee metadata
        ///</summary>
        /// <param name="committeeId">Committee ID </param>
        /// <param name="mustBeComplete">Whether committee must be complete (all votes ingested) </param>
        public async Task<Structs.CommitteeMetadata> GetCommitteeMetadata(byte[] committeeId, bool mustBeComplete, Account _tx_sender, ulong? _tx_fee, string _tx_note = "", ulong _tx_roundValidity = 1000, List<BoxRef>? _tx_boxes = null, List<Transaction>? _tx_transactions = null, List<ulong>? _tx_assets = null, List<ulong>? _tx_apps = null, List<Address>? _tx_accounts = null, AVM.ClientGenerator.Core.OnCompleteType _tx_callType = AVM.ClientGenerator.Core.OnCompleteType.NoOp)
        {
            _tx_boxes ??= new List<BoxRef>();
            _tx_transactions ??= new List<Transaction>();
            _tx_assets ??= new List<ulong>();
            _tx_apps ??= new List<ulong>();
            _tx_accounts ??= new List<Address>();
            byte[] abiHandle = { 55, 139, 43, 81 };
            var committeeIdAbi = new AVM.ClientGenerator.ABI.ARC4.Types.FixedArray<AVM.ClientGenerator.ABI.ARC4.Types.Byte>(32, "byte"); committeeIdAbi.From(committeeId);
            var mustBeCompleteAbi = new AVM.ClientGenerator.ABI.ARC4.Types.Bool(); mustBeCompleteAbi.From(mustBeComplete);

            var result = await base.SimApp(new List<object> { abiHandle, committeeIdAbi, mustBeCompleteAbi }, _tx_fee: _tx_fee, _tx_callType: _tx_callType, _tx_roundValidity: _tx_roundValidity, _tx_note: _tx_note, _tx_sender: _tx_sender, _tx_transactions: _tx_transactions, _tx_apps: _tx_apps, _tx_assets: _tx_assets, _tx_accounts: _tx_accounts, _tx_boxes: _tx_boxes);
            var lastLogBytes = result.Last();
            if (lastLogBytes.Length < 4 || lastLogBytes[0] != 21 || lastLogBytes[1] != 31 || lastLogBytes[2] != 124 || lastLogBytes[3] != 117) throw new Exception("Invalid ABI handle");
            return Structs.CommitteeMetadata.Parse(lastLogBytes.Skip(4).ToArray());

        }

